import { useState, useEffect, useContext, useRef } from "react"
import AppContext from "../../context"
import css from "./Master.module.css"
import Card from "../../components/Card/Card"
import backgroundCard from "../../assets/images/backgroundCardBlue.jpg"
import Popup from "../../components/Popup/Popup"
import { FaEdit } from "react-icons/fa"
import { FormMachineEntity, MachineEntity } from "../../entities/MachineEntity"
import { PopUpPilihEntity } from "../../components/Popup/PopupPilihEntity"
import PopupPilih from "../../components/Popup/PopupPilih"
import ExcelUtils from "../../utils/excel"
import { AlertEntity } from "../../layouts/Alert/AlertEntity"
import { FaSortDown, FaSortUp } from "react-icons/fa6"
import filterUtils from "../../utils/filter-utils"
import { GrPowerReset } from "react-icons/gr"
import { LinkUpService } from "../../services/link_up"
import { MachineService } from "../../services/machine"
import { LinkUpEntity } from "../../entities/LinkUpEntity"
import { FormMachineConfigFoll, MachineConfigFoll } from "../../entities/FollowingErrorEntity"
import { FollErrService } from "../../services/following_error"
import PopupInputData from "../../components/InputData/InputDataElement"

export default function MasterMachine() {
    // ========================================= GLOBAL CONTEXT =========================================  //
    const context = useContext(AppContext)
    const contextVersion = context.version
    const contextAccessToken = context.contextAccessToken
    const contextShowAlertFunc = context.contextShowAlertFunc
    const contextShowLoadingFunc = context.contextShowLoadingFunc
    const stateShowLoading = context.stateShowLoading
    // ========================================= GLOBAL CONTEXT =========================================  //


    // ========================================= STATE VIEW =========================================  //
    interface MachineCombined extends MachineEntity, MachineConfigFoll { }

    const [tableData, setTableData] = useState<MachineCombined[]>([])
    const [tableDataCache, setTableDataCache] = useState<MachineCombined[]>([])

    const [selectedData, setSelectedData] = useState<MachineCombined | null>(null)
    const [formData, setFormData] = useState<FormMachineEntity | null>(null)
    const [formDataFoll, setFormDataFoll] = useState<FormMachineConfigFoll | null>(null)

    const [showPopup, setShowPopup] = useState(false)
    const [showPopupPilih, setShowPopupPilih] = useState(false)
    const [popUpPilihEntity, setPopUpPilihEntity] = useState<PopUpPilihEntity>()

    const [sortColumn, setSortColumn] = useState<keyof MachineCombined | null>(null)
    const [sortType, setSortType] = useState<"ascending" | "descending">("ascending")
    const [tableDataFilter, setTableDataFilter] = useState<{ [key: string]: string }>({})
    // ========================================= STATE VIEW =========================================  //

    // ========================================= FUNCTIONS =========================================  //
    // ========================================= FUNCTIONS =========================================  //

    // TABLE AND FORMS //
    const handleSelectLinkUp = async () => {
        contextShowLoadingFunc(true)
        setShowPopup(false)

        try {
            const resp = await LinkUpService.GetAllLinkUp()

            setPopUpPilihEntity(new PopUpPilihEntity({
                popupTitle: 'Select Link Up',
                tableContent: resp,
                onClick: (row: LinkUpEntity) => {
                    setFormData((prevState: FormMachineEntity | null) => {
                        return { ...prevState, link_up_id: row.link_up_id, link_up: row.link_up }
                    })
                    setShowPopup(true)
                },
                onClose: () => { setShowPopupPilih(false); setShowPopup(true) }
            }))
            setShowPopupPilih(true)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    const handleFilterAndSort = async () => {
        const resp = tableDataCache
        const table_filtered = resp.filter((row) => {
            return filterUtils.FilterTable(row, tableDataFilter)
        }).sort((a, b) => {
            if (!sortColumn) return 0
            if (sortType == "ascending") {
                return filterUtils.SortingTable(a, b, sortColumn)
            } else {
                return filterUtils.SortingTable(b, a, sortColumn)
            }
        })
        setTableData(table_filtered)
    }

    const filterTable = (column: keyof MachineCombined, columnnName?: string) => {
        return <div>
            <input style={{ fontSize: "12px", marginTop: "0.5dvh", maxWidth: "500px" }} type="text" value={tableDataFilter[column] ?? ""}
                placeholder={`${columnnName ?? column} ...`}
                onChange={(event) => {
                    setTableDataFilter((prev) => {
                        const newData = { ...prev }
                        newData[column] = event.target.value
                        return newData
                    })
                }}
            />
        </div>
    }

    const headerTable = (column: keyof MachineCombined, columnName?: string) => {
        return <>
            <div style={{ display: "flex", flexDirection: "row", justifyContent: "center", gap: "3px", whiteSpace: "nowrap", cursor: "pointer" }}
                onClick={() => {
                    setSortColumn(column)
                    if (sortType === "ascending") {
                        setSortType("descending")
                    } else {
                        setSortType("ascending")
                    }
                }}
            >
                <div>{columnName ?? column}</div>
                <div style={{ display: "flex", flexDirection: "column", gap: "0", alignItems: "center", justifyItems: "center" }}>
                    <FaSortUp style={{ color: ((sortColumn == column && sortType == "descending") ? "var(--secondary-color)" : "silver"), margin: 0, padding: 0, height: '18px' }} />
                    <FaSortDown style={{ color: ((sortColumn == column && sortType == "ascending") ? "var(--secondary-color)" : "silver"), margin: "-18px", padding: 0, height: '18px' }} />
                </div>
            </div>
        </>
    }

    const resetAllForm = () => {
        setFormData(null)
        setFormDataFoll(null)
    }

    const handleShowPopup = (row?: MachineEntity) => {
        resetAllForm()
        setSelectedData(row ?? null)
        setShowPopup(true)
    }

    useEffect(() => {
        handleFilterAndSort()
    }, [tableDataFilter, sortColumn, sortType])

    // TABLE AND FORMS //

    // CRUD SERVICES //
    const handleSaveAdd = async () => {
        contextShowLoadingFunc(true)

        try {
            if (formData == null) { throw new Error("Please fill in all forms!") }

            if (formData.machine == null) { throw new Error("Please fill machine!") }
            if (formData.link_up_id == null) { throw new Error("Please fill link_up_id!") }
            if (formData.machine_type == null) { throw new Error("Please fill machine_type!") }
            if (formData.gateway_host == null) { throw new Error("Please fill gateway_host!") }
            if (formData.gateway_port == null) { throw new Error("Please fill gateway_port!") }
            if (formData.machine_warn == null) { throw new Error("Please fill machine_warn!") }
            if (formData.machine_alarm == null) { throw new Error("Please fill machine_alarm!") }

            const resp = await MachineService.AddMachine({
                machine: formData.machine,
                link_up_id: formData.link_up_id,
                machine_type: formData.machine_type,
                gateway_host: formData.gateway_host,
                gateway_port: formData.gateway_port,
                pressure_slave_id: formData.pressure_slave_id,
                vibration_slave_id: formData.vibration_slave_id,
                machine_warn: formData.machine_warn,
                machine_alarm: formData.machine_alarm,
            })

            await generateData()
            setSelectedData(null)
            resetAllForm()
            setShowPopup(false)
            contextShowAlertFunc(new AlertEntity({ message: resp.message, level: 1 }))
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    const handleSaveUpdate = async () => {
        contextShowLoadingFunc(true)

        try {
            if (selectedData == null) { throw new Error("Please fill in all forms!") }

            if (formData != null) {
                await MachineService.UpdateMachine(selectedData.machine_id, formData)
            }
            if (contextVersion.following != null && formDataFoll != null) {
                await FollErrService.UpsertMachineConfig(selectedData.machine_id, formDataFoll)
            }

            await generateData()
            setSelectedData(null)
            resetAllForm()
            setShowPopup(false)
            contextShowAlertFunc(new AlertEntity({ message: "[Success]", level: 1 }))
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    const handleDelete = async () => {
        return contextShowAlertFunc(new AlertEntity({
            message: `Are you sure you want to delete ${selectedData?.machine} ?`,
            onOk: async () => {
                contextShowLoadingFunc(true)

                try {
                    if (selectedData == null) return
                    const resp = await MachineService.DeleteMachine(selectedData.machine_id)

                    await generateData()
                    setSelectedData(null)
                    setShowPopup(false)
                    contextShowAlertFunc(new AlertEntity({ message: resp.message, level: 1 }))
                } catch (error: any) {
                    contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
                } finally {
                    contextShowLoadingFunc(false)
                }
            },
            withCancel: true,
            withOk: true,
            level: 2
        }))
    }

    const generateData = async () => {
        contextShowLoadingFunc(true)
        try {
            const resp: MachineCombined[] = await MachineService.GetAllMachine()

            if (contextVersion.following != null) {
                const foll = await FollErrService.GetMachineConfig()
                const mapped: { [machine_id: string]: MachineConfigFoll } = {}
                for (let i = 0; i < foll.length; i++) {
                    mapped[foll[i].machine_id] = foll[i]
                }

                for (let i = 0; i < resp.length; i++) {
                    resp[i] = { ...resp[i], ...mapped[resp[i].machine_id] }
                }
            }

            setTableData(resp)
            setTableDataCache(resp)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    useEffect(() => {
        generateData()
    }, [contextAccessToken])

    // CRUD SERVICES //


    // IMPORT EXPORT EXCEL //
    const handleGenerateExcel = async () => {
        if (tableData.length == 0) { return contextShowAlertFunc(new AlertEntity({ message: "NO DATA!", level: 3 })); }

        const column = [
            "machine_id", "machine", "link_up", "machine_type",
            "gateway_host", "gateway_port",
            "pressure_slave_id", "vibration_slave_id"
        ]
        let values: { [key: string]: string }[] = []
        for (let i = 0; i < tableData.length; i++) {
            values.push({
                machine_id: `${tableData[i].machine_id}`,
                machine: tableData[i].machine,
                link_up: tableData[i].link_up,
                machine_type: tableData[i].machine_type,
                gateway_host: tableData[i].gateway_host,
                gateway_port: tableData[i].gateway_port,
                pressure_slave_id: `${tableData[i].pressure_slave_id}`,
                vibration_slave_id: `${tableData[i].vibration_slave_id}`,
            })
        }

        ExcelUtils.export(`Master Machine List`, column, values)
    }

    // IMPORT EXPORT EXCEL //

    // ========================================= FUNCTIONS =========================================  //
    // ========================================= FUNCTIONS =========================================  //

    return (
        <>
            <div className="container" style={{ display: stateShowLoading ? "none" : "flex", backgroundColor: "transparent" }}>

                <div style={{ height: "94dvh", maxHeight: "100vh", display: "flex", flexDirection: "column" }}>

                    {/* Card Header */}
                    <div style={{ flexBasis: "auto" }} className="ordering-card">
                        <Card
                            detailTitle="Master Machine"
                            detailColor="var(--secondary-color)"
                            backgroundImage={backgroundCard}
                            stateShow={true}
                            detailCard={
                                <>
                                    <div className={css.rowGrid} style={{ alignItems: 'end' }}>
                                        <div>
                                            <div style={{ color: "white", textAlign: "start" }}>Action :</div>
                                            <button className="cardButton" onClick={() => handleShowPopup()} >
                                                Add New
                                            </button>
                                        </div>
                                        <div>
                                            <button className="cardButton" onClick={() => handleGenerateExcel()} >
                                                Generate Excel
                                            </button>
                                        </div>
                                        <div>
                                            <button className="cardButton" onClick={() => { setTableDataFilter({}); generateData(); setSortColumn(null); setSortType("descending") }} >
                                                <GrPowerReset /> &nbsp; Reset Filter
                                            </button>
                                        </div>
                                    </div>
                                </>
                            }
                        />
                    </div>

                    {/* Table */}
                    <div style={{ flex: 1, overflowY: "auto" }} className="ordering-table">
                        <table className="tableclickcell">
                            <thead>
                                <tr>
                                    <th colSpan={10}>MASTER MACHINE</th>
                                    {contextVersion.following != null && <th colSpan={2}>FOLLOWING ERROR</th>}
                                    <th rowSpan={2} style={{ backgroundColor: "var(--header-color)", width: "7dvw", maxWidth: "7dvw", minWidth: "7dvw", position: "sticky", right: 0, zIndex: 1 }}>Action</th>
                                </tr>
                                <tr>
                                    <th>
                                        {headerTable("machine_id")}
                                        {filterTable("machine_id")}
                                    </th>
                                    <th style={{ width: "150%" }}>
                                        {headerTable("machine")}
                                        {filterTable("machine")}
                                    </th>
                                    <th>
                                        {headerTable("link_up")}
                                        {filterTable("link_up")}
                                    </th>
                                    <th>
                                        {headerTable("machine_warn")}
                                        {filterTable("machine_warn")}
                                    </th>
                                    <th>
                                        {headerTable("machine_alarm")}
                                        {filterTable("machine_alarm")}
                                    </th>
                                    <th>
                                        {headerTable("machine_type")}
                                        {filterTable("machine_type")}
                                    </th>
                                    <th>
                                        {headerTable("gateway_host")}
                                        {filterTable("gateway_host")}
                                    </th>
                                    <th>
                                        {headerTable("gateway_port")}
                                        {filterTable("gateway_port")}
                                    </th>
                                    <th>
                                        {headerTable("pressure_slave_id")}
                                        {filterTable("pressure_slave_id")}
                                    </th>
                                    <th>
                                        {headerTable("vibration_slave_id")}
                                        {filterTable("vibration_slave_id")}
                                    </th>
                                    {/* FOLLOWING ERROR */}
                                    {contextVersion.following != null && <>
                                        <th>
                                            {headerTable("following_error_warn")}
                                            {filterTable("following_error_warn")}
                                        </th>
                                        <th>
                                            {headerTable("following_error_alarm")}
                                            {filterTable("following_error_alarm")}
                                        </th>
                                    </>}
                                </tr>
                            </thead>
                            {tableData.length > 0
                                ? <tbody>
                                    {tableData.map((row, index) => {
                                        return (
                                            <tr key={index}>
                                                <td>{row.machine_id}</td>
                                                <td>{row.machine}</td>
                                                <td>{row.link_up}</td>
                                                <td>{row.machine_warn}</td>
                                                <td>{row.machine_alarm}</td>
                                                <td>{row.machine_type}</td>
                                                <td>{row.gateway_host}</td>
                                                <td>{row.gateway_port}</td>
                                                <td>{row.pressure_slave_id}</td>
                                                <td>{row.vibration_slave_id}</td>

                                                {/* FOLLOWING ERROR */}
                                                {contextVersion.following != null && <>
                                                    <td>{row.following_error_warn}</td>
                                                    <td>{row.following_error_alarm}</td>
                                                </>}
                                                <td className={css.buttonFixAction} onClick={() => { handleShowPopup(row) }}>
                                                    <FaEdit /> Edit
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                                : <tbody><tr><td colSpan={1000}>No Data Available Yet !</td></tr></tbody>
                            }
                        </table>
                    </div>

                </div>


                {/* Popup Detail */}
                <Popup
                    setShowPopup={setShowPopup}
                    showPopup={showPopup}
                    popupTitle={selectedData == null ? "Add New" : `Edit ${selectedData?.machine}`}
                    popupContent={<>
                        <div className={css.bodyPopup}>
                            <div className={css.containerForm}>
                                {/* MASTER */}
                                <div className={css.containerFormItem}>
                                    <div>
                                        <div className={css.label}> Link Up<span style={{ color: "red" }}>*</span></div>
                                        <input className={css.inputedit} type="text" readOnly
                                            value={formData?.link_up ?? selectedData?.link_up ?? ""}
                                            onClick={handleSelectLinkUp}
                                        />
                                    </div>

                                    <PopupInputData
                                        label={"Machine"} value={formData?.machine} original_value={selectedData?.machine ?? ''}
                                        type_input={'text'} attribute={"machine"} required={true} setFormData={setFormData}
                                    />
                                    <PopupInputData
                                        label={"Machine Warn"} value={formData?.machine_warn} original_value={selectedData?.machine_warn ?? ''}
                                        type_input={'number'} attribute={"machine_warn"} required={true} setFormData={setFormData}
                                    />
                                    <PopupInputData
                                        label={"Machine Alarm"} value={formData?.machine_alarm} original_value={selectedData?.machine_alarm ?? ''}
                                        type_input={'number'} attribute={"machine_alarm"} required={true} setFormData={setFormData}
                                    />
                                    <div>
                                        <div className={css.label}>Type<span style={{ color: "red" }}>*</span></div>
                                        <select
                                            className={css.inputedit}
                                            value={formData?.machine_type ?? selectedData?.machine_type ?? ''}
                                            onChange={(e) => {
                                                setFormData((prev) => ({
                                                    ...prev,
                                                    machine_type: e.target.value
                                                }))
                                            }}
                                            required
                                        >
                                            <option value="" disabled>Select Type</option>
                                            <option value="Packer">Packer</option>
                                            <option value="Maker">Maker</option>
                                        </select>
                                    </div>
                                    <PopupInputData
                                        label={"Gateway Host"} value={formData?.gateway_host} original_value={selectedData?.gateway_host ?? ''}
                                        type_input={'text'} attribute={"gateway_host"} required={true} setFormData={setFormData}
                                    />
                                    <PopupInputData
                                        label={"Gateway Port"} value={formData?.gateway_port} original_value={selectedData?.gateway_port ?? ''}
                                        type_input={'text'} attribute={"gateway_port"} required={true} setFormData={setFormData}
                                    />
                                    <PopupInputData
                                        label={"Pressure Slave Id"} value={formData?.pressure_slave_id} original_value={selectedData?.pressure_slave_id ?? ''}
                                        type_input={'number'} attribute={"pressure_slave_id"} required={true} setFormData={setFormData}
                                    />
                                    <PopupInputData
                                        label={"Vibration Slave Id"} value={formData?.vibration_slave_id} original_value={selectedData?.vibration_slave_id ?? ''}
                                        type_input={'number'} attribute={"vibration_slave_id"} required={true} setFormData={setFormData}
                                    />
                                </div>

                                {/* FOLLOWING ERROR */}
                                {contextVersion.following != null && selectedData != null && (
                                    <>
                                        <div style={{ marginTop: "15px", marginBottom: "10px", width: "100%", height: "5px", backgroundColor: "#2d545e" }}></div>

                                        <div className={css.containerFormItem}>
                                            <PopupInputData
                                                label={"Following Error Warn"} value={formDataFoll?.following_error_warn} original_value={selectedData?.following_error_warn ?? ''}
                                                type_input='float' attribute="following_error_warn" required={true} setFormData={setFormDataFoll}
                                            />
                                            <PopupInputData
                                                label={"Following Error Alarm"} value={formDataFoll?.following_error_alarm} original_value={selectedData?.following_error_alarm ?? ''}
                                                type_input='float' attribute="following_error_alarm" required={true} setFormData={setFormDataFoll}
                                            />
                                        </div>
                                    </>
                                )}
                            </div>
                        </div>

                        <div className={css.footerPopup}>
                            <div className={css.buttons2}>
                                <div className={css.left}>
                                    <button className="tertiaryButton" onClick={() => { setShowPopup(false) }} >
                                        Close
                                    </button>
                                </div>
                                {selectedData != null &&
                                    <div className={css.right}>
                                        <button className="secondaryButton" onClick={() => handleDelete()}>
                                            Delete
                                        </button>
                                    </div>
                                }
                                <div className={css.right}>
                                    <button className="primaryButton"
                                        onClick={() => { selectedData ? handleSaveUpdate() : handleSaveAdd() }} >
                                        Save
                                    </button>
                                </div>
                            </div>
                        </div>
                    </>
                    }
                />

                {popUpPilihEntity != null
                    ? <PopupPilih
                        showPopup={showPopupPilih}
                        setShowPopup={setShowPopupPilih}
                        popUpPilihEntity={popUpPilihEntity}
                    />
                    : <></>}


            </div>
        </>
    );
}
